import React, {useState} from 'react'
import styled from 'styled-components'
import DesignerDropDown from '../components/DesignerDropDown'

const NavBarWrapper = styled.div `
width:90vw;
margin:0 auto;
height:30px;
display:flex;
justify-content:space-between;
align-items:center;
font-size:0.9rem;
padding:5px;
`

const Line = styled.div `
height:1px;
width:100vw;
background-color:rgba(0, 0, 0, 0.2);
`

const Designers = styled.div `
&:hover {
	cursor:pointer;
}
`
const MensWear = styled.div `
&:hover {
	cursor:pointer;
}
`
const WomensWear = styled.div `
&:hover {
	cursor:pointer;
}
`
const Sneakers = styled.div `
&:hover {
	cursor:pointer;
}
`
const Accessories = styled.div `
&:hover {
	cursor:pointer;
}
`

export default function Navbar () {
	const [isActive, setIsActive] = useState(false)


	const onDesignerEnter = () => {
		setIsActive(true)
	}

	const onDesignerLeave = () => {
		setIsActive(false)
	}

	return (
		<>
		<Line />
		<NavBarWrapper>
			<Designers onMouseEnter={onDesignerEnter} onMouseLeave={onDesignerLeave}>DESIGNERS</Designers>
			<DesignerDropDown isActive={isActive}/>
			<MensWear>MENSWEAR</MensWear>
			<WomensWear>WOMENSWEAR</WomensWear>
			<Sneakers>SNEAKERS</Sneakers>
			<Accessories>ACCESSORIES</Accessories>
		</NavBarWrapper>
		<Line />
		</>


	)
}
